const items = $input.all();
if (items.length === 0 || !items[0].json.data) {
  return [];
}
const html = items[0].json.data;
const now = new Date();
const currentDay = now.getDay();
const diffToMonday = currentDay === 0 ? -6 : 1 - currentDay;
const mondayDate = new Date(now);
mondayDate.setDate(now.getDate() + diffToMonday);
mondayDate.setHours(0, 0, 0, 0);
const nextMondayDate = new Date(mondayDate);
nextMondayDate.setDate(mondayDate.getDate() + 7);
const articles = [];
const rawItems = html.split('<div class="result_item">');
const titleRegex = /<h2>(.*?)<\/h2>/;
const linkTagRegex = /<a[^>]+class="item_cover"[^>]*>/; 
const hrefRefex = /href="([^\"\\"]+)"/;
const dateRegex = /class="item_date">(.*?)<\/div>/;
const categoryRegex = /class="item_type"[^>]*>(.*?)<\/a>/;
for (let i = 1; i < rawItems.length; i++) {
  const itemHtml = rawItems[i];
  const titleMatch = itemHtml.match(titleRegex);
  const dateMatch = itemHtml.match(dateRegex);
  const categoryMatch = itemHtml.match(categoryRegex);
  let link = null;
  const linkTagMatch = itemHtml.match(linkTagRegex);
  if (linkTagMatch) {
     const hrefMatch = linkTagMatch[0].match(hrefRefex);
     if (hrefMatch) link = hrefMatch[1];
  }
  if (titleMatch && link && dateMatch && categoryMatch) {
    const title = titleMatch[1].trim();
    const dateStr = dateMatch[1].trim();
    const category = categoryMatch[1].trim();
    const parts = dateStr.split('-');
    if (parts.length === 3) {
        const articleDate = new Date(parseInt(parts[0], 10), parseInt(parts[1], 10) - 1, parseInt(parts[2], 10));
        if (articleDate >= mondayDate && articleDate < nextMondayDate) {
            let brand = '其他';
            if (category === '消費者洞察') brand = 'iBuzz(消費者洞察)';
            else if (category === '網紅行銷策略') brand = 'Asia KOL';
            else if (category === '數據分析解方') brand = '業務提供';
            else if (category === '社群粉絲團健檢') brand = 'Fans Feed';
            const full_link = link.startsWith('http') ? link : 'https://www.i-buzz.com.tw' + link;
            articles.push({ json: { title: title, date: dateStr, brand: brand, full_link: full_link } });
        }
    }
  }
}
return articles;
